// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("POST "+options.BaseURL+"/api/auth/change-password", wrapper.ChangePassword)
	m.HandleFunc("POST "+options.BaseURL+"/api/auth/login", wrapper.Login)
	m.HandleFunc("POST "+options.BaseURL+"/api/auth/logout", wrapper.Logout)
	m.HandleFunc("GET "+options.BaseURL+"/api/auth/me", wrapper.GetAuthMe)
	m.HandleFunc("GET "+options.BaseURL+"/api/cameras", wrapper.ListCameras)
	m.HandleFunc("GET "+options.BaseURL+"/api/cameras/{name}", wrapper.GetCamera)
	m.HandleFunc("POST "+options.BaseURL+"/api/cameras/{name}/doorbell", wrapper.PressDoorbell)
	m.HandleFunc("POST "+options.BaseURL+"/api/cameras/{name}/ptz", wrapper.SendPTZCommand)
	m.HandleFunc("GET "+options.BaseURL+"/api/cameras/{name}/snapshot", wrapper.GetCameraSnapshot)
	m.HandleFunc("GET "+options.BaseURL+"/api/cameras/{name}/thumbnail", wrapper.GetCameraThumbnail)
	m.HandleFunc("GET "+options.BaseURL+"/api/cameras/{name}/zones", wrapper.ListZones)
	m.HandleFunc("POST "+options.BaseURL+"/api/cameras/{name}/zones", wrapper.CreateZone)
	m.HandleFunc("DELETE "+options.BaseURL+"/api/cameras/{name}/zones/{zone}", wrapper.DeleteZone)
	m.HandleFunc("PUT "+options.BaseURL+"/api/cameras/{name}/zones/{zone}", wrapper.UpdateZone)
	m.HandleFunc("GET "+options.BaseURL+"/api/cameras/{name}/zones/{zone}/presence", wrapper.GetZonePresence)
	m.HandleFunc("GET "+options.BaseURL+"/api/events", wrapper.ListEvents)
	m.HandleFunc("GET "+options.BaseURL+"/api/events/counts", wrapper.GetEventCounts)
	m.HandleFunc("GET "+options.BaseURL+"/api/events/stream", wrapper.GetEventStream)
	m.HandleFunc("GET "+options.BaseURL+"/api/events/{id}", wrapper.GetEvent)
	m.HandleFunc("POST "+options.BaseURL+"/api/events/{id}/assign-person", wrapper.AssignPersonToEvent)
	m.HandleFunc("GET "+options.BaseURL+"/api/events/{id}/clip", wrapper.GetEventClip)
	m.HandleFunc("POST "+options.BaseURL+"/api/events/{id}/clip", wrapper.ReextractClip)
	m.HandleFunc("GET "+options.BaseURL+"/api/events/{id}/detection-crop", wrapper.GetEventDetectionCrop)
	m.HandleFunc("POST "+options.BaseURL+"/api/events/{id}/identify", wrapper.IdentifyEvent)
	m.HandleFunc("GET "+options.BaseURL+"/api/events/{id}/snapshot", wrapper.GetEventSnapshot)
	m.HandleFunc("POST "+options.BaseURL+"/api/events/{id}/track-person", wrapper.TrackPerson)
	m.HandleFunc("GET "+options.BaseURL+"/api/health", wrapper.GetHealth)
	m.HandleFunc("GET "+options.BaseURL+"/api/health/live", wrapper.GetHealthLive)
	m.HandleFunc("GET "+options.BaseURL+"/api/health/ready", wrapper.GetHealthReady)
	m.HandleFunc("GET "+options.BaseURL+"/api/openapi.json", wrapper.GetOpenAPISpec)
	m.HandleFunc("GET "+options.BaseURL+"/api/system", wrapper.GetSystem)
	m.HandleFunc("POST "+options.BaseURL+"/api/system/recompress/trigger", wrapper.TriggerRecompression)
	m.HandleFunc("POST "+options.BaseURL+"/api/tokens", wrapper.CreateToken)
	m.HandleFunc("DELETE "+options.BaseURL+"/api/tokens/{id}", wrapper.DeleteToken)
	m.HandleFunc("GET "+options.BaseURL+"/metrics", wrapper.GetMetrics)

	return m
}

