// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Change the current user's password
	// (POST /api/auth/change-password)
	ChangePassword(ctx context.Context, request ChangePasswordRequestObject) (ChangePasswordResponseObject, error)
	// Authenticate with username and password
	// (POST /api/auth/login)
	Login(ctx context.Context, request LoginRequestObject) (LoginResponseObject, error)
	// End the current session
	// (POST /api/auth/logout)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Get the current authenticated principal
	// (GET /api/auth/me)
	GetAuthMe(ctx context.Context, request GetAuthMeRequestObject) (GetAuthMeResponseObject, error)
	// List all cameras
	// (GET /api/cameras)
	ListCameras(ctx context.Context, request ListCamerasRequestObject) (ListCamerasResponseObject, error)
	// Get camera detail
	// (GET /api/cameras/{name})
	GetCamera(ctx context.Context, request GetCameraRequestObject) (GetCameraResponseObject, error)
	// Trigger a doorbell press event
	// (POST /api/cameras/{name}/doorbell)
	PressDoorbell(ctx context.Context, request PressDoorbellRequestObject) (PressDoorbellResponseObject, error)
	// Send a PTZ command to a camera
	// (POST /api/cameras/{name}/ptz)
	SendPTZCommand(ctx context.Context, request SendPTZCommandRequestObject) (SendPTZCommandResponseObject, error)
	// Get live camera snapshot
	// (GET /api/cameras/{name}/snapshot)
	GetCameraSnapshot(ctx context.Context, request GetCameraSnapshotRequestObject) (GetCameraSnapshotResponseObject, error)
	// Get recording thumbnail at a given time
	// (GET /api/cameras/{name}/thumbnail)
	GetCameraThumbnail(ctx context.Context, request GetCameraThumbnailRequestObject) (GetCameraThumbnailResponseObject, error)
	// List zones for a camera
	// (GET /api/cameras/{name}/zones)
	ListZones(ctx context.Context, request ListZonesRequestObject) (ListZonesResponseObject, error)
	// Create a zone for a camera
	// (POST /api/cameras/{name}/zones)
	CreateZone(ctx context.Context, request CreateZoneRequestObject) (CreateZoneResponseObject, error)
	// Delete a zone
	// (DELETE /api/cameras/{name}/zones/{zone})
	DeleteZone(ctx context.Context, request DeleteZoneRequestObject) (DeleteZoneResponseObject, error)
	// Update a zone
	// (PUT /api/cameras/{name}/zones/{zone})
	UpdateZone(ctx context.Context, request UpdateZoneRequestObject) (UpdateZoneResponseObject, error)
	// Get presence state for a zone
	// (GET /api/cameras/{name}/zones/{zone}/presence)
	GetZonePresence(ctx context.Context, request GetZonePresenceRequestObject) (GetZonePresenceResponseObject, error)
	// List detection events
	// (GET /api/events)
	ListEvents(ctx context.Context, request ListEventsRequestObject) (ListEventsResponseObject, error)
	// Get event counts by label and camera
	// (GET /api/events/counts)
	GetEventCounts(ctx context.Context, request GetEventCountsRequestObject) (GetEventCountsResponseObject, error)
	// Server-sent event stream
	// (GET /api/events/stream)
	GetEventStream(ctx context.Context, request GetEventStreamRequestObject) (GetEventStreamResponseObject, error)
	// Get a single event
	// (GET /api/events/{id})
	GetEvent(ctx context.Context, request GetEventRequestObject) (GetEventResponseObject, error)
	// Assign a known person to an event or ignore it
	// (POST /api/events/{id}/assign-person)
	AssignPersonToEvent(ctx context.Context, request AssignPersonToEventRequestObject) (AssignPersonToEventResponseObject, error)
	// Download event video clip
	// (GET /api/events/{id}/clip)
	GetEventClip(ctx context.Context, request GetEventClipRequestObject) (GetEventClipResponseObject, error)
	// Re-extract event clip from recording segments
	// (POST /api/events/{id}/clip)
	ReextractClip(ctx context.Context, request ReextractClipRequestObject) (ReextractClipResponseObject, error)
	// Get cropped detection region from event snapshot
	// (GET /api/events/{id}/detection-crop)
	GetEventDetectionCrop(ctx context.Context, request GetEventDetectionCropRequestObject) (GetEventDetectionCropResponseObject, error)
	// Identify object in event using re-identification embeddings
	// (POST /api/events/{id}/identify)
	IdentifyEvent(ctx context.Context, request IdentifyEventRequestObject) (IdentifyEventResponseObject, error)
	// Get event snapshot image with bounding box overlay
	// (GET /api/events/{id}/snapshot)
	GetEventSnapshot(ctx context.Context, request GetEventSnapshotRequestObject) (GetEventSnapshotResponseObject, error)
	// Create a person record from an event detection
	// (POST /api/events/{id}/track-person)
	TrackPerson(ctx context.Context, request TrackPersonRequestObject) (TrackPersonResponseObject, error)
	// Full health check
	// (GET /api/health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Liveness probe
	// (GET /api/health/live)
	GetHealthLive(ctx context.Context, request GetHealthLiveRequestObject) (GetHealthLiveResponseObject, error)
	// Readiness probe
	// (GET /api/health/ready)
	GetHealthReady(ctx context.Context, request GetHealthReadyRequestObject) (GetHealthReadyResponseObject, error)
	// OpenAPI specification
	// (GET /api/openapi.json)
	GetOpenAPISpec(ctx context.Context, request GetOpenAPISpecRequestObject) (GetOpenAPISpecResponseObject, error)
	// System information
	// (GET /api/system)
	GetSystem(ctx context.Context, request GetSystemRequestObject) (GetSystemResponseObject, error)
	// Trigger manual recompression
	// (POST /api/system/recompress/trigger)
	TriggerRecompression(ctx context.Context, request TriggerRecompressionRequestObject) (TriggerRecompressionResponseObject, error)
	// Create a new API token
	// (POST /api/tokens)
	CreateToken(ctx context.Context, request CreateTokenRequestObject) (CreateTokenResponseObject, error)
	// Revoke an API token
	// (DELETE /api/tokens/{id})
	DeleteToken(ctx context.Context, request DeleteTokenRequestObject) (DeleteTokenResponseObject, error)
	// Prometheus metrics
	// (GET /metrics)
	GetMetrics(ctx context.Context, request GetMetricsRequestObject) (GetMetricsResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// ChangePassword operation middleware
func (sh *strictHandler) ChangePassword(w http.ResponseWriter, r *http.Request) {
	var request ChangePasswordRequestObject

	var body ChangePasswordJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.ChangePassword(ctx, request.(ChangePasswordRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "ChangePassword")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(ChangePasswordResponseObject); ok {
		if err := validResponse.VisitChangePasswordResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

